  const [layout, setLayout] = useState<CanvasDiffLayout>('split');
  const [wrapLines, setWrapLines] = useState(false);
  const diffQuery = useQuery(
    sessionCanvasDiffQueryOptions({
      enabled: props.active,
      projectId: props.target.projectId,
      sessionId: props.target.sessionId,
    })
  );
  const diffOptions = useMemo<FileDiffOptions<undefined>>(
    () => ({
      collapsedContextThreshold: 3,
      diffIndicators: 'bars',
      diffStyle: layout,
      hunkSeparators: 'line-info',
      lineDiffType: 'word',
      overflow: wrapLines ? 'wrap' : 'scroll',
      stickyHeader: true,
      theme: {
        dark: 'pierre-dark',
        light: 'pierre-light',
      },
    }),
    [layout, wrapLines]
  );

  if (!props.target.sessionId) {
    return (
      <CanvasDiffPlaceholder
        title="No session selected"
        detail={props.target.cwd ?? 'Select a worker session to review changes.'}
      />
    );
  }

  if (diffQuery.isPending) {
    return (
      <CanvasDiffPlaceholder
        title="Loading diff"
        detail={props.target.cwd ?? 'Reading the selected worktree.'}
      />
    );
  }

  if (diffQuery.isError) {
    return (
      <CanvasDiffPlaceholder
        title="Unable to load diff"
        detail={
          diffQuery.error instanceof Error
            ? diffQuery.error.message
            : 'The selected worktree diff could not be loaded.'
        }
      />
    );
  }

  if (diffQuery.data.patchTruncated) {
    return (
      <CanvasDiffShell
        layout={layout}
        snapshot={diffQuery.data}
        wrapLines={wrapLines}
        isRefreshing={diffQuery.isFetching}
        onLayoutChange={setLayout}
        onRefresh={() => void diffQuery.refetch()}
        onWrapLinesChange={setWrapLines}
      >
        <CanvasDiffPlaceholder
          title="Patch too large"
          detail="Open this session in an IDE to review the full diff."
        />
      </CanvasDiffShell>
    );
  }

  if (diffQuery.data.patch.trim() === '') {
    return (
      <CanvasDiffShell
        layout={layout}
        snapshot={diffQuery.data}
        wrapLines={wrapLines}
        isRefreshing={diffQuery.isFetching}
        onLayoutChange={setLayout}
        onRefresh={() => void diffQuery.refetch()}
        onWrapLinesChange={setWrapLines}
      >
        <CanvasDiffPlaceholder
          title={diffQuery.data.files.length === 0 ? 'No changes' : 'No text hunks'}
          detail={
            diffQuery.data.files.length === 0
              ? diffQuery.data.cwd
              : 'The changed files do not have renderable text hunks.'
          }
        />
      </CanvasDiffShell>
    );
  }

  return (
    <CanvasDiffShell
      layout={layout}
      snapshot={diffQuery.data}
      wrapLines={wrapLines}
      isRefreshing={diffQuery.isFetching}
      onLayoutChange={setLayout}
      onRefresh={() => void diffQuery.refetch()}
      onWrapLinesChange={setWrapLines}
    >
      <Virtualizer
        className="yyork-diff-virtualizer min-h-0 flex-1 overflow-auto"
        contentClassName="yyork-diff-virtualizer-content"
      >
        <PatchDiff
          className="yyork-diff-viewer"
          options={diffOptions}
          patch={diffQuery.data.patch}
        />
      </Virtualizer>
    </CanvasDiffShell>
  );
}

function CanvasDiffShell(props: {
  children: React.ReactNode;
  isRefreshing: boolean;
  layout: CanvasDiffLayout;
  snapshot: CanvasDiffSnapshot;
  wrapLines: boolean;
  onLayoutChange: (layout: CanvasDiffLayout) => void;
  onRefresh: () => void;
  onWrapLinesChange: (wrap: boolean) => void;
}) {
  const summary = getDiffSummary(props.snapshot);

  return (
    <section
      aria-label="Session diff"
      className="flex h-full min-h-0 max-w-full flex-col bg-background"
    >
      <div className="flex min-h-10 shrink-0 items-center gap-2 border-b border-border px-2 py-1.5">
        <div className="min-w-0 flex-1">
          <h3 className="truncate text-xs leading-4 font-medium text-foreground">
            {summary.title}
          </h3>
          <p className="truncate text-2xs leading-4 text-muted-foreground">
            {summary.detail}
          </p>
        </div>
        <div
          className="inline-flex shrink-0 rounded-sm bg-muted p-0.5"
          role="group"
          aria-label="Diff layout"
        >
          <Button
            type="button"
            variant={props.layout === 'split' ? 'secondary' : 'ghost'}
            size="xs"
            className="h-6 rounded-sm px-1.5 text-xs shadow-none"
            aria-pressed={props.layout === 'split'}
            onClick={() => props.onLayoutChange('split')}
          >
            <Columns2Icon data-icon="inline-start" aria-hidden="true" />
            <span>Split</span>
          </Button>
          <Button
            type="button"
            variant={props.layout === 'unified' ? 'secondary' : 'ghost'}
            size="xs"
            className="h-6 rounded-sm px-1.5 text-xs shadow-none"
            aria-pressed={props.layout === 'unified'}
            onClick={() => props.onLayoutChange('unified')}
          >
            <Rows3Icon data-icon="inline-start" aria-hidden="true" />
            <span>Stacked</span>
          </Button>
        </div>
        <Tooltip>
          <TooltipTrigger
            render={
              <Toggle
                type="button"
                variant="default"
                size="icon-sm"
                pressed={props.wrapLines}
                className="size-7 rounded-sm"
                aria-label="Toggle line wrapping"
                onPressedChange={props.onWrapLinesChange}
              />
            }
          >
            <WrapTextIcon aria-hidden="true" />
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p>Toggle line wrapping</p>
          </TooltipContent>
        </Tooltip>
        <Tooltip>
          <TooltipTrigger
            render={
              <Button
                type="button"
                variant="ghost"
                size="icon-xs"
                className="size-7 rounded-sm text-muted-foreground hover:text-foreground"
                aria-label="Refresh diff"
                loading={props.isRefreshing}
                onClick={props.onRefresh}
              />
            }
          >
            <RefreshCwIcon aria-hidden="true" />
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p>Refresh diff</p>
          </TooltipContent>
        </Tooltip>
      </div>
      <div className="min-h-0 flex-1 overflow-hidden">{props.children}</div>
    </section>
  );
}

function getDiffSummary(snapshot: CanvasDiffSnapshot) {
  const totals = snapshot.files.reduce(
    (accumulator, file) => ({
      additions: accumulator.additions + file.additions,
      deletions: accumulator.deletions + file.deletions,
    }),
    { additions: 0, deletions: 0 }
  );
  const fileLabel =
    snapshot.files.length === 1 ? '1 file' : `${snapshot.files.length} files`;
  const changeLabel = [
    totals.additions > 0 ? `+${totals.additions}` : undefined,
    totals.deletions > 0 ? `-${totals.deletions}` : undefined,
  ]
    .filter(Boolean)
    .join(' ');

  return {
    detail: changeLabel ? `${fileLabel} · ${changeLabel}` : snapshot.cwd,
    title: snapshot.baseLabel ? `Changes from ${snapshot.baseLabel}` : 'Changes',
  };
}

function CanvasDiffPlaceholder(props: {
  className?: string;
  detail: string;
  title: string;
}) {
  return (
    <div
      className={cn(
        'flex h-full min-h-0 max-w-full flex-col gap-2 p-3 text-sm leading-5',
        props.className
      )}
    >
      <h3 className="font-medium">{props.title}</h3>
      <p className="break-all text-muted-foreground">{props.detail}</p>
    </div>
  );
}

